function pickLocaleText(dict,loc){if(!dict)return'';loc=String(loc||'').replace('_','-');var base=loc.split('-')[0];return dict[loc]||dict[base]||(base==='zh'?dict['zh-CN']:base==='en'?dict['en-US']:'')||dict['zh-CN']||dict['en-US']||'';}
function tt(key,fallback,vars){var dict=PLUGIN_I18N&&PLUGIN_I18N[key],s=pickLocaleText(dict,locale())||fallback||key;if(vars)Object.keys(vars).forEach(function(k){s=String(s).replace(new RegExp('\\{'+k+'\\}','g'),vars[k]);});return s;}
function badgeLabel(productName){return productName+' '+tt('badge.verifiedBuyer','Verified Buyer');}
function cfgArray(v){if(Array.isArray(v))return v;if(typeof v==='string'){try{var parsed=JSON.parse(v);return Array.isArray(parsed)?parsed:[];}catch(e){return[];}}return[];}
function purchaseUrl(){var u=String(PLUGIN_CFG.purchase_url||DEFAULT_PURCHASE_URL).trim();return /^https?:\/\//i.test(u)?u:DEFAULT_PURCHASE_URL;}
function products(){var p=cfgArray(PLUGIN_CFG.products);return p.map(function(x){return{key:String(x&&x.key||'').trim(),name:String(x&&x.name||x&&x.label||x&&x.key||'').trim(),icon:String(x&&x.icon||DEFAULT_ICON).trim(),color:String(x&&x.color||'#3fb950').trim(),description:String(x&&x.description||tt('badge.defaultDescription','FAB Marketplace purchase verification')).trim()};}).filter(function(x){return x.key&&x.name;});}
function productByKey(key){var k=slug(key,'');return products().find(function(p){return slug(p.key,'')===k;})||null;}
function activeStatus(item){var v=item&&item.value||{},d=item&&item.decision||{};return d.status||v.status||'pending';}
function usedProductKeys(list){var used={};(list||[]).forEach(function(item){var st=activeStatus(item);if(st==='rejected')return;var v=item.value||{},d=item.decision||{},k=slug(d.product_key||v.product_key||'','');if(k)used[k]=1;});return used;}
function productOptions(used){used=used||{};return products().filter(function(p){return !used[slug(p.key,'')];}).map(function(p){return'<option value="'+attr(p.key)+'">'+esc(p.name)+' · '+esc(p.key)+'</option>';}).join('');}
function esc(s){return String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/\"/g,'&quot;');}
