function slug(s,fallback){return String(s||'').trim().toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/^-+|-+$/g,'').slice(0,64)||fallback||'order';}
function orderKey(orderId){return 'order:'+slug(orderId,'order');}
