function apiMe(){return fetch(BASE+'/me').then(function(r){return r.ok?r.json():null;});}
function apiDb(body){var h={'Content-Type':'application/json'};if(typeof nonceHeaders==='function'){var n=nonceHeaders();h['X-Timestamp']=n['X-Timestamp'];h['X-Nonce']=n['X-Nonce'];}return fetch(BASE+'/db',{method:'POST',headers:h,body:JSON.stringify(body)}).then(function(r){return r.json().catch(function(){return{};}).then(function(d){if(!r.ok)throw new Error(d.error||'DB error '+r.status);return d;});});}
