function findString(obj,names,depth){if(!obj||depth>4)return'';if(Array.isArray(obj)){for(var i=0;i<obj.length;i++){var x=findString(obj[i],names,depth+1);if(x)return x;}return'';}if(typeof obj==='object'){for(var k in obj){if(names.indexOf(String(k).toLowerCase())>=0&&typeof obj[k]==='string'&&obj[k].trim())return obj[k].trim();}for(var k2 in obj){var y=findString(obj[k2],names,depth+1);if(y)return y;}}return'';}
function productFromOrder(order,selectedKey,orderId){var foundKey=findString(order,['product_id','productid','plugin_id','pluginid','asset_id','assetid','listing_id','listingid','slug','namespace'],0);var picked=productByKey(foundKey)||productByKey(selectedKey);if(!picked)picked={key:selectedKey,name:selectedKey,icon:DEFAULT_ICON,color:'#3fb950',description:tt('badge.defaultDescription','FAB Marketplace purchase verification')};return{product_name:picked.name,product_key:slug(picked.key,slug(orderId,'order')),product_icon:picked.icon,product_color:picked.color,product_description:picked.description,source_key:foundKey?'fab':'config'};}
