function bchip(b){var s=b.color?'border-color:'+esc(b.color)+'66;color:'+esc(b.color)+';background:'+esc(b.color)+'1f':'';var label=String(b&&b.label||'').trim();var fallback=(label||'?').slice(0,1).toUpperCase();var media=b.icon?(isImg(b.icon)?'<img class="badge-chip-img" src="'+attr(b.icon)+'" alt="">':'<span class="badge-chip-icon">'+esc(String(b.icon).slice(0,2))+'</span>'):'<span class="badge-chip-icon">'+esc(fallback)+'</span>';return'<span class="badge-chip badge-chip-icon-only"'+(s?' style="'+s+'"':'')+' title="'+attr(b.description||label||'')+'" aria-label="'+attr(label)+'">'+media+'</span>';}
async function decisionFor(userId,key){var d=await apiDb({op:'get',collection:'decisions',key:decisionKey(userId,key),scope:'shared'}).catch(function(){return null;});if(d&&d.found)return d.value;return null;}
async function userOrders(user){var res=await apiDb({op:'list',collection:'verify',limit:100}).catch(function(){return{items:[]};});var items=res.items||[];var out=[];for(var i=0;i<items.length;i++){var item=items[i],v=item.value||{};var dec=await decisionFor(user.id,item.key);if(!dec&&item.key==='pending'){var old=await apiDb({op:'get',collection:'decisions',key:'u'+user.id,scope:'shared'}).catch(function(){return null;});if(old&&old.found)dec=old.value;}out.push({key:item.key,value:v,decision:dec});}return out;}
