var slot=document.getElementById('ff-plugin-settings-slot');if(slot){slot.innerHTML='<div class="fab-card"><div class="fab-card-hd"><div class="fab-card-title"><h3>'+esc(tt('settings.title','FAB Purchase Verification'))+'</h3><p>'+esc(tt('settings.description','Orders are reviewed against products configured by the plugin. Approved orders grant matching badges.'))+'</p></div><div class="fab-card-actions"><a id="fab-order-help" class="btn fab-order-help" href="'+attr(purchaseUrl())+'" target="_blank" rel="noopener noreferrer" title="'+attr(tt('settings.viewOrderIdHint','Open Epic Games purchase history to find your order ID.'))+'">'+esc(tt('settings.viewOrderId','View order ID'))+'</a><button id="fab-submit" class="btn primary" type="button">'+esc(tt('settings.submit','Submit'))+'</button></div></div><div class="fab-card-body"><div id="fab-status" class="fab-status muted">'+esc(tt('settings.loading','Loading...'))+'</div><div class="fab-form"><input id="fab-order" type="text" placeholder="'+attr(tt('settings.orderPlaceholder','FAB order ID'))+'" autocomplete="off"><select id="fab-product-key"><option value="">'+esc(tt('settings.selectProduct','Select product'))+'</option>'+productOptions()+'</select></div><div id="fab-msg" style="min-height:18px;font-size:13px"></div></div></div>';var statusEl=document.getElementById('fab-status'),msgEl=document.getElementById('fab-msg'),btn=document.getElementById('fab-submit'),input=document.getElementById('fab-order'),prodKeyInput=document.getElementById('fab-product-key'),currentUser=null,currentOrders=[];function refreshProductOptions(list){currentOrders=list||[];var selected=prodKeyInput.value,opts=productOptions(usedProductKeys(currentOrders));prodKeyInput.innerHTML='<option value="">'+(opts?tt('settings.selectProduct','Select product'):tt('settings.noProducts','No products available'))+'</option>'+opts;if(selected&&Array.from(prodKeyInput.options).some(function(o){return o.value===selected;}))prodKeyInput.value=selected;btn.disabled=!opts;}async function reloadUser(){try{currentUser=await apiMe();if(!currentUser){statusEl.textContent=tt('settings.loginRequired','Please sign in first');return;}currentOrders=await userOrders(currentUser);statusEl.innerHTML=renderStatus(currentOrders);refreshProductOptions(currentOrders);}catch(e){statusEl.textContent=tt('settings.loadFailed','Failed to load');}}reloadUser();btn.addEventListener('click',async function(){var orderId=input.value.trim(),manualKey=prodKeyInput.value.trim();if(!orderId){msgEl.className='fab-err';msgEl.textContent=tt('settings.orderRequired','Enter an order ID');return;}if(!manualKey){msgEl.className='fab-err';msgEl.textContent=tt('settings.productRequired','Select a verification product');return;}if(usedProductKeys(currentOrders)[slug(manualKey,'')]){msgEl.className='fab-err';msgEl.textContent=tt('settings.duplicateProduct','This product is already requested or verified');refreshProductOptions(currentOrders);return;}btn.disabled=true;btn.textContent=tt('settings.verifying','Verifying...');msgEl.textContent='';try{var user=currentUser||await apiMe();if(!user)throw new Error(tt('settings.loginRequired','Please sign in first'));var result=await apiFetch('https://www.fab.com/seller/orders/v2?order_id='+encodeURIComponent(orderId),'GET',{cookie:'fab_sessionid'});var order=null,apiOk=!!result.ok,apiError='';if(result.body){try{order=JSON.parse(result.body);}catch(e){apiError=tt('settings.responseFormatError','FAB API response format error');}}if(!apiOk){apiError=tt('settings.requestFailed','FAB API request failed (HTTP {status})',{status:result.status});}if(order&&order.detail&&order.detail.orderId){apiError=tt('settings.apiReturned','FAB API returned: {detail}',{detail:String(order.detail.orderId.join?order.detail.orderId.join(', '):order.detail.orderId)});apiOk=false;}if(apiOk&&(!order||(Array.isArray(order.results)&&order.results.length===0))){apiError=tt('settings.notFound','Order not found');apiOk=false;}if(!apiOk&&!manualKey)throw new Error(tt('settings.pickProductAfterApiError','{error}; select a verification product and submit for review',{error:apiError}));var meta=productFromOrder(apiOk?order:null,manualKey,orderId);await apiDb({op:'set',collection:'verify',key:orderKey(orderId),value:{order_id:orderId,status:'pending',product_key:meta.product_key,product_name:meta.product_name,product_icon:meta.product_icon,product_color:meta.product_color,product_description:meta.product_description,product_source:meta.source_key,order_snippet:JSON.stringify(order||{api_error:apiError,manual_product_key:manualKey}).slice(0,1500),submitted_at:new Date().toISOString()}});input.value='';prodKeyInput.value='';msgEl.className='fab-warn';msgEl.textContent=tt('settings.submitted','Order submitted. Please wait for admin review');await reloadUser();}catch(e){msgEl.className='fab-err';msgEl.textContent=e.message||tt('settings.verifyFailed','Verification failed');}finally{btn.disabled=false;btn.textContent=tt('settings.submit','Submit');}});}
function createWb(root){root.innerHTML='<div class="admin-workbench"><div class="admin-toolbar"><span style="font-weight:750">'+esc(tt('admin.title','FAB purchase verification review'))+'</span><button class="btn btn-sm ml-auto" data-fab-ref>'+esc(tt('admin.refresh','Refresh'))+'</button></div><div class="admin-table-shell"><div class="admin-table-scroll"><table class="table" style="min-width:860px"><thead><tr><th style="width:80px">'+esc(tt('admin.userId','User ID'))+'</th><th style="width:210px">'+esc(tt('admin.orderId','Order ID'))+'</th><th style="width:190px">'+esc(tt('admin.product','Plugin/Product'))+'</th><th style="width:110px">'+esc(tt('admin.status','Status'))+'</th><th style="width:150px">'+esc(tt('admin.submittedAt','Submitted'))+'</th><th>'+esc(tt('admin.actions','Actions'))+'</th></tr></thead><tbody data-fab-tbd><tr><td colspan="6" style="text-align:center;padding:32px;color:var(--muted)">'+esc(tt('admin.loading','Loading...'))+'</td></tr></tbody></table></div><div class="admin-footer"><span data-fab-cnt style="color:var(--muted);font-size:13px"></span></div></div></div>';var tbody=root.querySelector('[data-fab-tbd]'),cnt=root.querySelector('[data-fab-cnt]'),ref=root.querySelector('[data-fab-ref]');async function load(){try{var res=await apiDb({op:'list',collection:'verify',all_users:true,limit:200});var items=res.items||[];var dr=await apiDb({op:'list',collection:'decisions',scope:'shared',key_prefix:'order:',limit:200}).catch(function(){return{items:[]};});var dec={};(dr.items||[]).forEach(function(d){dec[d.key]=d.value;});if(cnt)cnt.textContent=tt('admin.total','{count} order requests',{count:items.length});if(!items.length){tbody.innerHTML='<tr><td colspan="6" style="text-align:center;padding:32px;color:var(--muted)">'+esc(tt('admin.empty','No verification requests'))+'</td></tr>';return;}tbody.innerHTML=items.map(function(item){var v=item.value||{},dk=decisionKey(item.user_id,item.key),d=dec[dk]||{},st=d.status||v.status||'pending',bd=badgeFor(Ob