urn;var v=item.value||{},bd=badgeFor(v),dk=decisionKey(uid,key);b.disabled=true;b.textContent='…';try{await apiDb({op:'set',collection:'decisions',key:dk,value:{status:act==='approve'?'approved':'rejected',order_id:v.order_id,product_key:v.product_key,product_name:v.product_name,product_icon:bd.icon,product_color:bd.color,product_description:bd.description,badge_key:bd.badge_key,badge_label:bd.label,icon:bd.icon,color:bd.color,updated_at:new Date().toISOString()},scope:'shared'});if(act==='approve'){await apiDb({op:'grant_badge',badge_key:bd.badge_key,label:bd.label,description:bd.description,color:bd.color,icon:bd.icon,target_user_id:uid});}else{await apiDb({op:'revoke_badge',badge_key:bd.badge_key,target_user_id:uid}).catch(function(){});}await load();}catch(e){b.disabled=false;b.textContent=act==='approve'?tt('admin.approve','Approve'):tt('admin.reject','Reject');alert(tt('admin.actionFailed','Action failed: {error}',{error:e.message}));}});load();}
var adminRoot=document.getElementById('ff-plugin-admin-root');if(adminRoot){createWb(adminRoot);}var badgeTabs=(window.ForumForgePluginUI&&window.ForumForgePluginUI.registerBadgeTab)?window.ForumForgePluginUI:(window.FF_BadgePage&&window.FF_BadgePage.registerTab?window.FF_BadgePage:null);function refreshTabLabel(){var tab=document.querySelector('#ff-badge-tab-bar [data-btab=\"fab-verify\"]');if(tab)tab.textContent=tt('admin.tab','FAB verification');}if(badgeTabs&&badgeTabs.registerBadgeTab){badgeTabs.registerBadgeTab('fab-verify',tt('admin.tab','FAB verification'),function(panel){createWb(panel);});refreshTabLabel();window.addEventListener('forumforge:localechange',refreshTabLabel);}else if(badgeTabs&&badgeTabs.registerTab){badgeTabs.registerTab('fab-verify',tt('admin.tab','FAB verification'),function(panel){createWb(panel);});refreshTabLabel();window.addEventListener('forumforge:localechange',refreshTabLabel);}
